import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { orderAPI } from '../services/api';
import './Checkout.css';

// ✅ Matches backend modeOfPayment values exactly
const PAYMENT_METHODS = [
  { value: 'COD',         label: '💵 Cash on Delivery' },
  { value: 'UPI',         label: '📱 UPI' },
  { value: 'CREDIT_CARD', label: '💳 Credit Card' },
  { value: 'DEBIT_CARD',  label: '🏦 Debit Card' },
  { value: 'NET_BANKING', label: '🌐 Net Banking' },
];

export default function Checkout() {
  const { cartItems, totalPrice, totalItems, clearCart } = useCart();
  const { user } = useAuth();
  const toast    = useToast();
  const navigate = useNavigate();

  // ✅ Fields match backend PlaceOrderRequest exactly:
  // fullName, mobileNumber, flatNumber, city, pincode, state, modeOfPayment
  const [form, setForm] = useState({
    fullName:      user?.fullName || '',
    mobileNumber:  '',
    flatNumber:    '',
    city:          '',
    state:         '',
    pincode:       '',
    modeOfPayment: 'COD',
  });
  const [placing, setPlacing] = useState(false);
  const [errors,  setErrors]  = useState({});

  // Redirect if cart is empty
  if (!cartItems || cartItems.length === 0) {
    return (
      <div className="checkout-page">
        <div className="checkout-empty">
          <div className="empty-icon">🛒</div>
          <h2>Your cart is empty</h2>
          <p>Add some books before checking out.</p>
          <Link to="/books" className="btn-primary">Browse Books</Link>
        </div>
      </div>
    );
  }

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors(prev => ({ ...prev, [name]: '' }));
  };

  const validate = () => {
    const e = {};
    if (!form.fullName.trim())     e.fullName     = 'Full name is required';
    if (!form.mobileNumber.trim()) e.mobileNumber = 'Mobile number is required';
    else if (!/^\d{10}$/.test(form.mobileNumber.trim())) e.mobileNumber = 'Enter a valid 10-digit number';
    if (!form.flatNumber.trim())   e.flatNumber   = 'Flat/House number is required';
    if (!form.city.trim())         e.city         = 'City is required';
    if (!form.state.trim())        e.state        = 'State is required';
    if (!form.pincode.trim())      e.pincode      = 'Pincode is required';
    else if (!/^\d{6}$/.test(form.pincode.trim())) e.pincode = 'Enter a valid 6-digit pincode';
    return e;
  };

  const handlePlaceOrder = async () => {
    const e = validate();
    if (Object.keys(e).length > 0) {
      setErrors(e);
      toast.error('Please fill all required fields correctly');
      return;
    }

    // ✅ Payload matches PlaceOrderRequest exactly
    // ✅ items match OrderItemRequest: bookId, bookTitle, bookAuthor, price, quantity
    const payload = {
      fullName:      form.fullName.trim(),
      mobileNumber:  form.mobileNumber.trim(),
      flatNumber:    form.flatNumber.trim(),
      city:          form.city.trim(),
      state:         form.state.trim(),
      pincode:       form.pincode.trim(),
      modeOfPayment: form.modeOfPayment,
      items: cartItems.map(item => ({
        bookId:     item.bookId,
        bookTitle:  item.bookTitle,
        bookAuthor: item.bookAuthor || '',
        price:      item.price,
        quantity:   item.quantity,
      })),
    };

    setPlacing(true);
    try {
      await orderAPI.placeOrder(payload);
      await clearCart();
      toast.success('Order placed successfully! 🎉');
      navigate('/orders');
    } catch (err) {
      const msg = err.response?.data?.message || 'Failed to place order. Please try again.';
      toast.error(msg);
    } finally {
      setPlacing(false);
    }
  };

  return (
    <div className="checkout-page">
      <div className="checkout-container">

        {/* ── Left: Form ───────────────────────────────────────── */}
        <div className="checkout-form-section">

          {/* Delivery Address */}
          <div className="checkout-card">
            <h2 className="section-title">📦 Delivery Address</h2>

            <div className="form-group">
              <label>Full Name *</label>
              <input
                type="text"
                name="fullName"
                value={form.fullName}
                onChange={handleChange}
                placeholder="Enter your full name"
                className={errors.fullName ? 'input-error' : ''}
              />
              {errors.fullName && <span className="error-msg">{errors.fullName}</span>}
            </div>

            <div className="form-group">
              <label>Mobile Number *</label>
              <input
                type="tel"
                name="mobileNumber"
                value={form.mobileNumber}
                onChange={handleChange}
                placeholder="10-digit mobile number"
                maxLength={10}
                className={errors.mobileNumber ? 'input-error' : ''}
              />
              {errors.mobileNumber && <span className="error-msg">{errors.mobileNumber}</span>}
            </div>

            <div className="form-group">
              <label>Flat / House No. / Building *</label>
              <input
                type="text"
                name="flatNumber"
                value={form.flatNumber}
                onChange={handleChange}
                placeholder="House no., Building, Street, Area"
                className={errors.flatNumber ? 'input-error' : ''}
              />
              {errors.flatNumber && <span className="error-msg">{errors.flatNumber}</span>}
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>City *</label>
                <input
                  type="text"
                  name="city"
                  value={form.city}
                  onChange={handleChange}
                  placeholder="City"
                  className={errors.city ? 'input-error' : ''}
                />
                {errors.city && <span className="error-msg">{errors.city}</span>}
              </div>

              <div className="form-group">
                <label>State *</label>
                <input
                  type="text"
                  name="state"
                  value={form.state}
                  onChange={handleChange}
                  placeholder="State"
                  className={errors.state ? 'input-error' : ''}
                />
                {errors.state && <span className="error-msg">{errors.state}</span>}
              </div>

              <div className="form-group">
                <label>Pincode *</label>
                <input
                  type="text"
                  name="pincode"
                  value={form.pincode}
                  onChange={handleChange}
                  placeholder="6-digit pincode"
                  maxLength={6}
                  className={errors.pincode ? 'input-error' : ''}
                />
                {errors.pincode && <span className="error-msg">{errors.pincode}</span>}
              </div>
            </div>
          </div>

          {/* Payment Method */}
          <div className="checkout-card">
            <h2 className="section-title">💳 Payment Method</h2>
            <div className="payment-options">
              {PAYMENT_METHODS.map(pm => (
                <label
                  key={pm.value}
                  className={`payment-option ${form.modeOfPayment === pm.value ? 'selected' : ''}`}
                >
                  <input
                    type="radio"
                    name="modeOfPayment"
                    value={pm.value}
                    checked={form.modeOfPayment === pm.value}
                    onChange={handleChange}
                  />
                  <span>{pm.label}</span>
                </label>
              ))}
            </div>
          </div>
        </div>

        {/* ── Right: Order Summary ─────────────────────────────── */}
        <div className="checkout-summary-section">
          <div className="checkout-card summary-card">
            <h2 className="section-title">🛒 Order Summary</h2>

            <div className="summary-items">
              {cartItems.map((item) => (
                <div key={item.itemId} className="summary-item">
                  <div className="summary-item-info">
                    <span className="summary-item-title">{item.bookTitle}</span>
                    <span className="summary-item-qty">x{item.quantity}</span>
                  </div>
                  <span className="summary-item-price">
                    ₹{(item.price * item.quantity).toFixed(2)}
                  </span>
                </div>
              ))}
            </div>

            <div className="summary-divider" />

            <div className="summary-row">
              <span>Items ({totalItems})</span>
              <span>₹{totalPrice?.toFixed(2)}</span>
            </div>
            <div className="summary-row">
              <span>Delivery</span>
              <span className="free-tag">FREE</span>
            </div>

            <div className="summary-divider" />

            <div className="summary-row summary-total">
              <span>Total</span>
              <strong>₹{totalPrice?.toFixed(2)}</strong>
            </div>

            <button
              className="place-order-btn"
              onClick={handlePlaceOrder}
              disabled={placing}
            >
              {placing ? 'Placing Order…' : '✅ Place Order'}
            </button>

            <Link to="/cart" className="back-to-cart">
              ← Back to Cart
            </Link>
          </div>
        </div>

      </div>
    </div>
  );
}
